var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"해, 해냈어. 괴수들이 물러난다!","JPN":"や、やった。怪獣が退いていく！","ENG":"W-we did it! The monsters are retreating!","TWN":"成功了，我們成功了。怪獸們撤退了！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"전부 해치웠어! 우리가 이긴 거야!","JPN":"全部やっつけたぞ！　俺たちが勝ったんだ！","ENG":"They're all down! We won!","TWN":"全部解決了！我們贏了！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"우리가… 정말 이긴 건가?","JPN":"本当に私たちが……勝ったのか？","ENG":"Did... Did we really win?","TWN":"我們……真的贏了嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하하! 대장님, 설마 우시는 거 아니죠?","JPN":"はは！　隊長、まさか泣いてないですよね？","ENG":"Haha! Don't tell me you're crying, Captain!","TWN":"哈哈！隊長，你不會哭了吧？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"야 인마. 소녀 같은 대장님 마음에 상처를 입히면 어떡해?","JPN":"おい、乙女のような隊長の心を傷つけちゃダメだろう？","ENG":"Hey, come on. Don't wound the tender heart of our maidenly Captain!","TWN":"喂，臭小子。隊長可是少女心，你這樣受傷。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"저흰 괜찮습니다, 대장님. 어차피 투구에 가려져서 보이지도 않으니 마음껏 우세요.","JPN":"私たちは大丈夫ですよ、隊長。どうせ兜のせいで見えませんから、思う存分泣いてください。","ENG":"We're fine, Captain. With those helmets on, no one can see anyway. Cry all you want.","TWN":"不用在乎我們，隊長。反正被頭盔遮住了也看不見，盡情哭吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전 소녀도 아니고, 운 적도 없습니다!","JPN":"私は乙女でもないし、泣いたこともありません！","ENG":"I am not a maiden, and I did not cry!","TWN":"我才不是少女心呢，我才沒哭！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……휴우.","JPN":"……ふう。","ENG":"...Phew.","TWN":"……呼。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"고생하셨습니다. 에스테로사 경 덕분에 별다른 피해 없이 끝났네요.","JPN":"お疲れ様でした。エステロサ卿のおかげで、大した被害もなく終わりましたね。","ENG":"Great work. Thanks to you, Dame Esterosa, we made it through with barely any casualties.","TWN":"你辛苦了。多虧了艾斯特洛索，我們才能毫無損傷地結束這次事件。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아닙니다. 여러분이 노력하신 덕분이죠.","JPN":"いいえ。皆さんが頑張ってくれたおかげです。","ENG":"No, it was all of you. Your efforts made it possible.","TWN":"不，這都是你們努力的結果。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전부 끝났으니, 이제 돌아가면…….","JPN":"すべて終わりましたので、もう戻れば……","ENG":"It's all over now. So we can finally head ba–","TWN":"既然都結束了，現在回去吧……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어……?","JPN":"えっ……？","ENG":"...Huh?","TWN":"呃……？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"왜 그러십니까?","JPN":"どうしましたか？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아, 아닙니다. 방금 무척이나 섬뜩한 느낌이 든 것 같아서요.","JPN":"あ、いいえ。今、とてもぞっとするような気がして。","ENG":"I-It's nothing. I just felt something. A chill.","TWN":"啊，不是的。剛才好像有種非常毛骨悚然的感覺。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 느낌은, 마치…….","JPN":"この感覚は、まるで……","ENG":"It felt like...","TWN":"這個感覺，就像……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L27_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"응? 뭐야, 저 거인형 괴수는?","JPN":"うん？　なんだ、あの巨人型の怪獣は。","ENG":"Huh? What's that? A giant monster?","TWN":"嗯？什麼啊，那巨型怪獸是什麼？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"놓친 녀석이 남아있었나? 후딱 해치우고 돌아가자고.","JPN":"逃したやつがいたのか？　早くやっつけて戻ろう。","ENG":"Did one slip past us? Let's deal with it and head back.","TWN":"還有漏網之魚嗎？趕緊解決掉然後回去吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……안돼.","JPN":"……ダメだ。","ENG":"...No.","TWN":"不行……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"멈춰! 다들 움직이지 마!!","JPN":"止まれ！　みんな、動くな！！","ENG":"Don't move! Everyone stay back!!","TWN":"停下！大家都不要動！！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"喔？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"뭐야… 내 몸이 왜……?","JPN":"なんだ……体がどうして……？","ENG":"W-What's... happening to my body...?","TWN":"怎麼回事…我的身體怎麼了……？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"모… 몸이, 절단됐어?","JPN":"か……体が、切断された？","ENG":"My– My body's been cut in half?","TWN":"身……身體，被切斷了？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"저놈에게서 느껴지는 독기는, 서, 설마…….","JPN":"あいつから感じられる毒気は、ま、まさか……","ENG":"That poison I sense from it... I-it can't be...","TWN":"從那傢伙身上感受到的殺氣，難道是……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"……저.","JPN":"……ぜ。","ENG":"...Um.","TWN":"……那個"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"전원, 전투 준비! 마왕 네헤모트다!!","JPN":"全員、戦闘準備！　魔王ネヘモトだ！！","ENG":"Everyone, prepare for battle! It's the Demon Lord, Nehemoth!!","TWN":"全員，準備戰鬥！是魔王貝赫莫特！！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저 거인이 마왕 네헤모트라고?","JPN":"あの巨人が魔王ネヘモトだと？","ENG":"That giant is the Demon Lord Nehemoth?","TWN":"那個巨人是魔王貝赫莫特嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만, 네헤모트는 분명…!!","JPN":"でも、ネヘモトは確かに……！！","ENG":"But Nehemoth was supposed to be–!!","TWN":"但是，貝赫莫特不是…！！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"대장님. 아직 일출까지 3시간이나 남았습니다.","JPN":"隊長。日の出まではまだ3時間も残っています。","ENG":"Captain, it's still three hours until sunrise.","TWN":"隊長，距離日出還有3個小時呢。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"저희들 만으로 마왕을 상대하기는…….","JPN":"私たちだけで魔王を相手するのは……","ENG":"We can't handle the Demon Lord alone...","TWN":"僅憑我們自己來對付魔王……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예. 알고 있습니다.","JPN":"はい。わかっています。","ENG":"Yes, I'm well aware.","TWN":"沒錯，我知道。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"결국…… 저희 차례가 온 모양이군요.","JPN":"ついに……私たちの番が来たようですね。","ENG":"In the end... Our time has come, I suppose.","TWN":"看來……輪到我們了。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전원, 지금부터 부상자를 제외한 인원은 그레이스 경을 호위하러 이동합니다.","JPN":"全員、今から負傷者を除き、グレース卿を護衛するために移動します。","ENG":"Everyone who can still fight, move out to protect Dame Grace.","TWN":"全員，從現在開始，除受傷人員外，其他人都去保護葛瑞絲小姐。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"남은 병사들이 시간을 끌 동안 채비를 갖춰 제도에 복귀하세요.","JPN":"残りの兵士が時間を稼いでる間、準備して帝都に復帰するように。","ENG":"The rest will stall the enemy. Use the time to regroup and return to the capital.","TWN":"趁剩下的士兵拖延時間時，做好準備返回首都。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부상자들만 남는다니. 그게 무슨 말씀입니까?","JPN":"負傷者だけ残るって、どういうことですか？","ENG":"Leave the wounded behind? What do you mean?","TWN":"只剩下傷患嗎？這是什麼意思？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"단지 시간을 끌 뿐이니 걱정하실 필요 없습니다.","JPN":"ただの時間稼ぎですので、心配する必要はありません。","ENG":"We're only buying time. There's no need to worry.","TWN":"只是拖延時間而已，不必擔心。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"가는 도중 침식체를 맞닥트릴 수 있으니, 서둘러 출발하시죠.","JPN":"道の途中で侵食体と出くわす可能性もありますので、急いで出発してください。","ENG":"You may encounter C.O.s on the way. You should move quickly.","TWN":"在路上可能會遇到侵蝕體，趕快出發吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"대장님. 이번 출정에 대해 언니분께는 아무 말씀도 안 드렸다고 들었습니다.","JPN":"隊長。今回の出征について、お姉さんに何も話していないと聞きました。","ENG":"Captain, I heard you never told your sister about this mission.","TWN":"隊長。我聽說你沒有告訴姊姊這次出征的事情。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"정말 괜찮으시겠어요?","JPN":"本当に大丈夫なのですか？","ENG":"Are you really all right with that?","TWN":"真的沒問題嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그렇기에 더더욱, 부끄러운 모습을 보이고 싶지 않군요.","JPN":"ですからなおさら、恥ずかしい姿を見せたくありません。","ENG":"That's exactly why I don't want to show her a shameful end.","TWN":"正因為如此，我更不想丟人現眼。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"……예, 그렇죠.","JPN":"……はい、そうですよね。","ENG":"...Right.","TWN":"……是的，沒錯。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"함께 싸울 수 있어서 영광이었습니다, 페론 경.","JPN":"ともに戦うことができて光栄でした、ペロン卿。","ENG":"It's been an honor fighting beside you, Sir Ferron.","TWN":"能與你並肩作戰是我的榮幸，費隆卿。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠시만요, 저는…!!","JPN":"待ってください、私は……！！","ENG":"Wait, I...!!","TWN":"等一下，我……！！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"가시죠. 에스테로사 경.","JPN":"行きましょう、エステロサ卿。","ENG":"Let's go, Dame Esterosa.","TWN":"走吧，艾斯特洛索。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"저희가 믿지 않으면, 대체 누가 동료들을 믿겠습니까?","JPN":"私たち以外に、誰が仲間たちを信じるというのですか？","ENG":"If we don't trust them, who will?","TWN":"如果我們不相信，那還有誰會相信我們的夥伴呢？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모든 이야기는 의문으로부터 시작되는 법이니 당장 이해하실 필요는 없습니다.","JPN":"すべての話は疑問から始まるものですので、今すぐ理解なさる必要はありません。","ENG":"Every story begins with a question. There's no need to understand right away.","TWN":"所有故事都是從疑問開始的，所以不必急於理解。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 확실한 건, 경의 추측대로 이곳은 과거의 기억의 재현이며.","JPN":"確かなのは、卿の推測どおり、ここは過去の記憶の再現であり。","ENG":"But you were right. This place is a reconstruction of the past as you speculated.","TWN":"但可以確定的是，正如你的推測，這裡是過去記憶的再現。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 이야기의 끝에 다다르면, 어떤 형태로든 경께서는 진실에 다다르실 겁니다.","JPN":"卿はその話の最後に、どのような形であろうと真実にたどり着くことになるでしょう。","ENG":"And when the story reaches its end, you'll reach the truth in one form or another.","TWN":"當你走到故事的盡頭時，無論以何種形式，你都會接觸到真相。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"기다리고 있겠습니다, 페론 경.","JPN":"待っています、ペロン卿。","ENG":"I'll be waiting, Sir Ferron.","TWN":"我們會等著你，費隆卿。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예. 그레이스 경을 부탁드립니다.","JPN":"はい。グレース卿をよろしくお願いします。","ENG":"Of course. Take care of Dame Grace.","TWN":"好，葛瑞絲小姐就交給你了。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"작별 인사할 시간을 주다니. 생각보다 자비로우시군, 마왕.","JPN":"別れの挨拶をする時間を与えてくれるとは。思ったより慈悲深いのだな、魔王。","ENG":"So, you give us time for farewells. How merciful, Demon Lord.","TWN":"居然給我時間道別。比我想像中要仁慈啊，魔王。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아니면, 우리들은 상대할 가치조차 없단 건가?","JPN":"それとも、私たちは相手する価値すらないということか？","ENG":"Or maybe, we're simply not worth your effort at all?","TWN":"或者說，我們根本不值得對方出手嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"헛된 희망을 품고 있군.","JPN":"無駄な希望に過ぎんというのに。","ENG":"You cling to foolish hope.","TWN":"你懷有不切實際的希望啊。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네놈의 무가치한 희생으로는 현실을 바꿀 수 없다.","JPN":"そなたの価値のない犠牲では現実を変えることはできない。","ENG":"Your worthless sacrifice will change nothing.","TWN":"你的無謂犧牲無法改變現實。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"상관없다. 지금은 그저, 네놈을 이곳에 일분 일초라도 더 붙잡을 뿐이야.","JPN":"構わない。今はただ、貴様をここに1分、1秒でも止めておくだけだ。","ENG":"That's fine. All I need to do is keep you here, just for one second longer.","TWN":"無所謂。現在我只想讓你在這裡多待一分一秒。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그게 그레이스 경이 주신, 내 두 번째 삶의 이유다.","JPN":"それがグレース卿が与えてくれた、私の2度目の人生の理由だ。","ENG":"That's the second meaning of life that Dame Grace gave me.","TWN":"那就是葛瑞絲小姐賜予我第二次生命的意義。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그런가.","JPN":"そうか。","ENG":"I see.","TWN":"是嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그렇다면 나 또한, 그 각오에 응해야겠지.","JPN":"それなら我もまた、その覚悟に応えるべきであろう。","ENG":"Then I too shall honor your resolve.","TWN":"那麼我也應該回應這樣的決心吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"기사들이여! 이곳이 우리의 소임을 다할 마지막 전장이다!","JPN":"騎士たちよ！　ここが私たちの任務を果たす最後の戦場だ！","ENG":"Knights! This is our final battlefield, where we fulfill our duty!","TWN":"騎士們！這裡是我們履行職責的最後戰場！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"먼 훗날, 우리의 의지를 이어 새로운 희망을 움켜쥘 자들을 위해.","JPN":"遠い未来、私たちの意志を受け継いで新しい希望を手にする者たちのために。","ENG":"So that those who carry our will may seize new hope one day!","TWN":"在遙遠的未來，為了那些繼承我們的意志並抓住新希望的人。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"우리들의 긍지를, 이곳에 새기는 거다!!","JPN":"私たちの誇りを、ここに刻むのだ！！","ENG":"Let our pride be carved into this land!!","TWN":"將我們的榮譽銘刻於此！！"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"별을 추종하는 로웰의 페론.","JPN":"星の追従者、ローウェルのペロン。","ENG":"Ferron of the House of Lowell, follower of the stars.","TWN":"追隨星辰的勞威爾家費隆。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……이곳에서 마지막 별의 인도를 따르겠나이다.","JPN":"……ここで最後の星の導きに従います。","ENG":"...Here, I will follow the final guidance of the stars.","TWN":"……在此地追隨最後星之引導者。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"허억… 허억…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼哧……呼哧……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"윽…!!","JPN":"うっ……！！","ENG":"Nngh...!!","TWN":"呃……！！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"거점에 있던 병사들도… 모두 당했어.","JPN":"拠点にいた兵士たちも……みんなやられてしまった。","ENG":"The soldiers at the base... they're all gone too.","TWN":"據點裡的士兵們……全都遭殃了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"마, 마왕의 독기에 침식체들이 반응한 건가?","JPN":"ま、魔王の毒気に侵食体が反応したのか？","ENG":"D-did the Demon Lord's poison trigger the C.O.s?","TWN":"魔王的毒氣讓侵蝕體有反應了嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"……하. 가뜩이나 말 많으신 분이 왜 이렇게 빨리 왔냐고 뭐라 하겠네.","JPN":"……は。おしゃべりな方だから、どうしてこんなに早く来たのかと怒られそうだな。","ENG":"*...Sigh* She'd give me an earful for showing up so fast.","TWN":"……哈。話多的人怎麼這麼快就來了，真是讓人無奈。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"에스테로사 경. 저희 백작님을 부탁드립니다.","JPN":"エステロサ卿。伯爵を頼みます。","ENG":"Dame Esterosa, please watch over the Countess.","TWN":"艾斯特洛索。請你照顧我們的伯爵大人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"기왕이면 몸값 두둑이 쳐서, 저희 누님에게 보내 달라고 말 좀 부탁드려요.","JPN":"どうせならありったけの慰謝料を私の姉に送ってくださるよう、お伝えくださいね。","ENG":"While you're at it, could you ask her to pay a hefty sum and send it to my sister?","TWN":"既然如此，請幫我轉告，讓他們給我姊姊多付一些酬勞。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이 정도 침식체라면 충분히 대응 가능합니다.","JPN":"この程度の侵食体なら、十分対応できます。","ENG":"These C.O.s aren't a problem.","TWN":"這種程度的侵蝕體應該可以應對。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"살아남은 자들끼리 힘을 합친다면…….","JPN":"生き残った者で力を合わせれば……","ENG":"As long as the survivors work together...","TWN":"如果倖存者們能齊心協力……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그러다 마왕이 따라잡으면 그거야말로 낭패입니다.","JPN":"それで魔王に追いつかれたら、それこそ大変です。","ENG":"But if the Demon Lord catches up, we're all done for.","TWN":"如果被魔王追上，那才是真正的麻煩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"저희 중에서 가장 강한 에스테로사 경이 아니면, 누가 그레이스 경을 지키겠습니까?","JPN":"私たちの中で一番強いエステロサ卿でないと、誰がグレース卿を守るんですか？","ENG":"If not you, Dame Esterosa, who else can protect Dame Grace?","TWN":"如果不是我們中最強的艾斯特洛索，誰能保護葛瑞絲小姐呢？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저 말은?","JPN":"あの馬は？","ENG":"That horse...","TWN":"那句話是？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"…클링턴 영감님. 뭐 좋다고 마지막까지 남아 계셨대?","JPN":"……クリントンのジジイ。なんでまた最後まで残ってたのかな。","ENG":"...Old man Clinton. Why'd he insist on staying behind?","TWN":"…克林頓先生，是有什麼好事你要留到最後？"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그래도 다행이네요. 말이 있다면 백작님이 계신 곳까지 빠르게 다다를 수 있을 겁니다.","JPN":"でもよかったですね。馬がいるなら、伯爵のところまでもっと早くたどり着けるでしょう。","ENG":"Still, it's a weight off my shoulders. With a horse, you'll reach the Countess in time.","TWN":"不過還好。有馬的話，就能快速到達伯爵所在的地方。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 백작령의 기사들인 여러분이 가지 않으면, 누가 그레이스 경을…….","JPN":"でも、伯爵領の騎士である皆さんが行かないと、誰がグレース卿を……","ENG":"But you're the knights of the County. If you don't go, who will protect Dame Grace...","TWN":"但是如果你們這些伯爵領地的騎士不去的話，誰來保護葛瑞絲小姐呢……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"봐주세요, 에스테로사 경.","JPN":"勘弁してください、エステロサ卿。","ENG":"Please, Dame Esterosa.","TWN":"請你多擔待，艾斯特洛索。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"마지막 정도는 체면 좀 차리고 싶습니다.","JPN":"最後くらいはカッコよく見せたいんです。","ENG":"Let us keep our pride, just this once.","TWN":"最後至少想要保留一點面子。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"말 고삐를 건넨 손에서, 뚜렷한 흔들림이 전해져 온다.","JPN":"馬の手綱を渡す手からは、目に見えるほどの震えが感じられる。","ENG":"As he handed me the reins, his hands trembled.","TWN":"從遞過韁繩的手中，傳來明顯的顫抖。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그제서야 투구 너머로, 두려움에 눈물 맺힌 기사의 표정을 눈치챘다.","JPN":"その時になってようやく、兜の向こう、恐怖で涙がにじんだ騎士の顔に気づいた。","ENG":"Only then did I notice that through his helmet, his eyes were glistening with fear.","TWN":"直到那時，我才注意到頭盔後面，那位騎士因恐懼而流淚的表情。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제게 맡기시죠.","JPN":"任せてください。","ENG":"Leave it to me.","TWN":"交給我吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"반드시 그레이스 경을 구하겠습니다.","JPN":"必ずグレース卿を助けます。","ENG":"I will protect Dame Grace.","TWN":"我一定會救出葛瑞絲小姐的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"감사합니다. 다음 생이란 게 있다면 그때도 함께 싸울 수 있으면 좋겠네요.","JPN":"ありがとうございます。来世があるなら、その時も一緒に戦えたらいいですね。","ENG":"Thank you. If there's such a thing as a next life, I hope we can fight together again.","TWN":"謝謝你。如果有來生的話，希望還能和你並肩作戰。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"저는 어중간한 실력이다 보니 죽도 같은 거나 주구장창 휘둘러야겠지만요.","JPN":"私は中途半端な実力なので、竹刀などを振り回すだけでしょうが。","ENG":"Even if I'm just swinging a something like a bamboo sword like always.","TWN":"我水準一般，只能一直揮舞像竹刀這樣的東西。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"죽기 싫다, 젠장.","JPN":"死にたくないなあ、くそ。","ENG":"Damn it. I don't want to die.","TWN":"我還不想死，該死的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"먼 길 오느라 고생 많으셨습니다.","JPN":"ここまでお越しになるとは思いませんでした。","ENG":"Thank you for coming all this way.","TWN":"大老遠地跑過來，辛苦你了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"얼굴을 마주하는 것은 처음이로군요, 마왕.","JPN":"顔を合わせるのは初めてですね、魔王。","ENG":"We meet face-to-face at last, Demon Lord.","TWN":"第一次面對面見面呢，魔王。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"……과연.","JPN":"……なるほど。","ENG":"...I see.","TWN":"……果然。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네가 당대의 별의 인도자로군.","JPN":"そなたが当代の星の導き手か。","ENG":"So you are the current Star Guide.","TWN":"你就是當代的星之引導者。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 기사들은 어찌 되었습니까?","JPN":"私の騎士たちはどうなったのでしょうか。","ENG":"What happened to my knights?","TWN":"我的騎士們怎麼樣了？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"바라 마지않는 안식을 위해, 모두 죽였다.","JPN":"念願の安息のため、皆殺した。","ENG":"I granted them the rest they longed for and killed everyone.","TWN":"當然是為了渴望已久的安息，殺了所有人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"미천한 이 한 몸 잡고자 마왕이 직접 나서다니 참으로 별난 일이로군요.","JPN":"下賤なこの私一人のために、魔王が直接手を下すとは、不思議な事もあるものです。","ENG":"For the Demon Lord himself to come for someone like me. How unusual.","TWN":"為了抓住我這卑微之身，魔王竟然親自出馬，真是稀奇的事情啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리도 인류의 반격이 무서우셨습니까?","JPN":"それほど人類の反撃が怖かったのですか？","ENG":"Were you that afraid of humanity's counterattack?","TWN":"難道你害怕人類的反擊嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네가 후세에 남길 희망의 불씨는 실로 역겨운 자취를 풍기고 있다.","JPN":"そなたが後世に残す希望の火種は実に悍ましい軌跡を見せている。","ENG":"The ember of hope you leave behind reeks of defiance.","TWN":"你留給後世的希望火種，實在是令人作嘔。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"설령 패배하더라도 끝이 아닐 거라는 희망… 그것이 내게는 너무나도 잔혹할 뿐.","JPN":"たとえ失敗しても終わりではないという希望……それが我にはあまりにも残酷だ。","ENG":"Hope that defeat isn't the end... That is unbearably cruel to me.","TWN":"即使失敗也不是終點的希望……這實在是太殘酷了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그리하여, 내가 그 영원한 윤회를 끊기 위해 직접 당도했다.","JPN":"それゆえ、我がその永遠の輪廻を断つために直接来たのだ。","ENG":"And so, I've come to sever that cycle myself.","TWN":"因此，我親自前來打破那永恆的輪回。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"이 세계의 모든 걸 말미암아 내가 바라는 최후를 맞이하기 위해.","JPN":"この世界のすべてをもって、我の望む最後を迎えるために。","ENG":"To bring about the ending I desire, through the end of this world.","TWN":"為了迎接我所期望的這個世界的終結。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"타인의 삶을 그토록 앗아간 자가 자신의 최후를 바라다니 모순적이군요.","JPN":"あれほど他人の人生を奪って来た者が、自分の最後を望むなんて矛盾ですね。","ENG":"A being who's stolen so many lives wishing for his own end. How contradictory.","TWN":"奪走他人生命的人竟然期待自己的終結，真是矛盾啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네놈이 별의 인도자라면 이것이 무한히 반복되는 굴레와 같다는 것을 알고 있을 터.","JPN":"そなたが星の導き手なら、これが無限に繰り返される束縛のようなものであるとわかっているはずだ。","ENG":"If you're the Star Guide, you should know that this is an eternal cycle.","TWN":"如果你是星之引導者，那麼你應該知道這就像是無盡重複的枷鎖。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그곳에서 헤어나올 수만 있다면 무엇이든 좋다.","JPN":"そこから逃げられるなら、何でも良い。","ENG":"I'd do anything to break free of it.","TWN":"只要能從那裡逃脫就行。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"설령, 내 손으로 세계를 멸망시키는 일이라고 할지라도.","JPN":"たとえ、自らの手で世界を滅ぼすことであろうとも。","ENG":"Even if it means destroying the world with my own hands.","TWN":"哪怕意味著要親手毀滅這個世界。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"자신의 숙명으로부터 벗어나기 위해 네놈도 누군가에게 그 업을 떠넘기려 했을 텐데?","JPN":"自分の宿命から逃げるため、そなたもまた誰かにその業を押しつけようとしたはずだが。","ENG":"Surely you too tried to cast off your fate by passing your burden onto someone else?","TWN":"為了擺脫自己的宿命，你也曾試圖將這份業障轉嫁給別人吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L2_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"네놈과 나는 다르지 않다.","JPN":"そなたと我は同じだ。","ENG":"You and I are no different.","TWN":"我和你沒有什麼不同。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그저 선악을 구분하는 경계선에 달리 있을 뿐.","JPN":"ただ善悪を区別する境界線の向こう側にいるだけ。","ENG":"We just stand on opposite sides of a fading line.","TWN":"只不過是在區分善惡的界限上奔跑而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 당신과는 다릅니다.","JPN":"私は貴方とは違います。","ENG":"I am nothing like you.","TWN":"我跟你不一樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"부질없는 발버둥을 택했군.","JPN":"無駄な足掻きを選んだか。","ENG":"So you choose a futile struggle.","TWN":"你選擇了無謂的掙扎。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그것이 네놈들의 패인이다.","JPN":"それがそなたらの敗因だ。","ENG":"That is why your kind will lose.","TWN":"那就是你們的敗因。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"별의 인도자로서 당신의 앞날을 하나 예언해드리지요.","JPN":"星の導き手として、貴方の未来を予言いたしましょう。","ENG":"Allow me to offer you a prophecy as the Star Guide.","TWN":"作為星之引導者，我將為你預言未來的一段旅程。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그대가 바라는 안식은 영영 찾아오지 않을 것입니다, 마왕.","JPN":"貴方が望む安息は永遠に訪れないでしょう、魔王。","ENG":"The peace you seek will never come, Demon Lord.","TWN":"你所渴望的安息將永遠不會到來，魔王。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"그렇다면 나 또한 마왕으로서 선언하지.","JPN":"なら、我もまた魔王として宣言しよう。","ENG":"Then I too shall proclaim, as the Demon Lord.","TWN":"那麼我也以魔王的身份宣告。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEHEMOTH_NPC_NULL_NULL","text":{"KOREA":"이 세계에서, 너희에게 구원이란 찾아오지 않는다.","JPN":"この世界で、そなたらに救いなど訪れない。","ENG":"In this world, there will be no salvation for your kind.","TWN":"在這個世界裡，救贖不會降臨到你們身上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEHEMOTH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};